		});
	}, options);

	const navLinks = document.querySelectorAll('a.nav-link[href^="#"]');
	navLinks.forEach((link) => {
		const id = link.hash.slice(1);
		const idContainer = document.querySelector(`[id="${id}"]`);
		if (idContainer) {
			observer.observe(idContainer);
		}
	});
});
